    /**
     * Resolve the `[1, cols]` style row for a voice (or comma-separated blend string)
     * at the given phoneme count.
     */
    fun `styleVector`(`voice`: kotlin.String, `phonemeCount`: kotlin.Long): StyleVector
    
    companion object
}

