                )
            2 -> PipelineException.SpeechEngine(
                FfiConverterString.read(buf),
                )
            3 -> PipelineException.VoiceLoader(
                FfiConverterString.read(buf),
                )
            4 -> PipelineException.InvalidSpeed(
                FfiConverterFloat.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: PipelineException): ULong {
        return when(value) {
            is PipelineException.JsonParse -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is PipelineException.SpeechEngine -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is PipelineException.VoiceLoader -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is PipelineException.InvalidSpeed -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterFloat.allocationSize(value.`speed`)
            )
        }
    }

    override fun write(value: PipelineException, buf: ByteBuffer) {
        when(value) {
            is PipelineException.JsonParse -> {
                buf.putInt(1)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is PipelineException.SpeechEngine -> {
                buf.putInt(2)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is PipelineException.VoiceLoader -> {
                buf.putInt(3)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is PipelineException.InvalidSpeed -> {
                buf.putInt(4)
                FfiConverterFloat.write(value.`speed`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
